import React from "react";
import { Link } from "react-router-dom";
import { Star, Play } from "lucide-react";
import { motion } from "framer-motion";

const AnimeCard = ({ anime, index }) => {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.9 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true }}
      transition={{ delay: index * 0.1, duration: 0.5 }}
    >
      <Link
        to={`/anime/${anime._id}`}
        className="group relative bg-[#ffffff]/80 dark:bg-cyber-gray/80 backdrop-blur-xl rounded-[2rem] overflow-hidden shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:shadow-[0_20px_40px_rgba(45,212,191,0.2)] dark:shadow-2xl dark:hover:shadow-cyber-teal/20 transition-all duration-500 block border border-white/50 dark:border-white/10"
      >
        <div className="aspect-[3/4] relative overflow-hidden">
          <motion.img
            whileHover={{ scale: 1.1 }}
            transition={{ duration: 0.8 }}
            src={anime.coverImage || anime.imageUrl}
            alt={anime.title}
            className="w-full h-full object-cover"
            loading="lazy"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent opacity-0 group-hover:opacity-100 dark:opacity-80 transition-opacity duration-300" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-cyber-teal/20 backdrop-blur-[2px]">
            <motion.div
              initial={{ scale: 0 }}
              whileHover={{ scale: 1.2 }}
              className="bg-cyber-teal text-cyber-black p-4 rounded-full shadow-xl"
            >
              <Play size={24} fill="currentColor" />
            </motion.div>
          </div>

          <div className="absolute top-4 right-4 bg-white/90 dark:bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full flex items-center space-x-1 border border-white/20 shadow-sm">
            <Star size={12} className="text-cyber-amber" fill="currentColor" />
            <span className="text-cyber-black dark:text-white text-xs font-black">
              {anime.score || "N/A"}
            </span>
          </div>
        </div>

        <div className="p-5 bg-transparent relative z-10 w-full">
          <h3 className="font-black text-cyber-black dark:text-white truncate text-lg group-hover:text-cyber-teal transition-colors tracking-tight uppercase italic">
            {anime.title}
          </h3>
          <div className="flex items-center space-x-2 mt-2">
            <span className="text-[10px] font-black tracking-widest uppercase text-cyber-teal bg-cyber-teal/10 px-2 py-0.5 rounded">
              {anime.status === "Currently Airing" ? "LIVE" : "VOD"}
            </span>
            <span className="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-widest">
              {anime.episodes ? `${anime.episodes} Episodes` : "Unknown Length"}
            </span>
          </div>
        </div>
      </Link>
    </motion.div>
  );
};

export default AnimeCard;

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Play, ChevronLeft, ChevronRight } from "lucide-react";
import { useNavigate } from "react-router-dom";

const HeroCinematic = ({ animes }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const navigate = useNavigate();

  // Auto-scroll logic
  useEffect(() => {
    if (!animes || animes.length === 0) return;
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % animes.length);
    }, 6000); // 6 seconds per slide
    return () => clearInterval(interval);
  }, [animes]);

  if (!animes || animes.length === 0) return null;

  const handleNext = () => {
    setCurrentIndex((prev) => (prev + 1) % animes.length);
  };

  const handlePrev = () => {
    setCurrentIndex((prev) => (prev - 1 + animes.length) % animes.length);
  };

  const handleNavigate = () => {
    navigate(`/anime/${animes[currentIndex]._id}`);
  };

  return (
    <section className="relative h-screen min-h-100 lg:min-h-150 w-full overflow-hidden bg-transparent">
      <AnimatePresence mode="wait">
        {/* The image container */}
        <div className="absolute inset-0 w-full h-full">
          <motion.div
            key={currentIndex}
            initial={{ opacity: 0, scale: 1.05 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 1.2, ease: "easeInOut" }}
            className="absolute inset-0 bg-cover bg-top md:bg-center"
            style={{
              backgroundImage: `url(${animes[currentIndex]?.bannerImage || animes[currentIndex]?.imageUrl})`,
            }}
          />
        </div>
      </AnimatePresence>

      {/* Premium Cinematic Deep Vignette for Text Contrast */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(0,0,0,0.2)_0%,rgba(2,6,23,0.95)_100%)] bg-linear-to-t from-cyber-black via-cyber-black/90 to-black/40 z-10" />

      {/* Carousel Controls */}
      <div className="absolute inset-y-0 left-0 z-30 flex items-center px-4 md:px-8">
        <button
          onClick={handlePrev}
          className="p-3 md:p-4 rounded-full bg-black/20 hover:bg-cyber-teal border border-white/10 hover:border-cyber-teal backdrop-blur-md text-white hover:text-cyber-black transition-all duration-300 group"
        >
          <ChevronLeft
            size={32}
            className="group-hover:-translate-x-1 transition-transform"
          />
        </button>
      </div>

      <div className="absolute inset-y-0 right-0 z-30 flex items-center px-4 md:px-8">
        <button
          onClick={handleNext}
          className="p-3 md:p-4 rounded-full bg-black/20 hover:bg-cyber-teal border border-white/10 hover:border-cyber-teal backdrop-blur-md text-white hover:text-cyber-black transition-all duration-300 group"
        >
          <ChevronRight
            size={32}
            className="group-hover:translate-x-1 transition-transform"
          />
        </button>
      </div>

      <div className="absolute inset-0 flex flex-col justify-end pb-32 px-16 md:px-24 lg:px-32 z-20 pointer-events-none">
        <AnimatePresence mode="wait">
          <motion.div
            key={`text-${currentIndex}`}
            initial={{ y: 60, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -60, opacity: 0 }}
            transition={{ duration: 0.8, ease: "easeOut" }}
            className="max-w-5xl space-y-6 pointer-events-auto"
          >
            <div className="flex flex-wrap items-center gap-4">
              <span className="px-4 py-1.5 bg-cyber-teal/10 border border-cyber-teal/30 text-cyber-teal text-xs font-black tracking-widest uppercase rounded-full backdrop-blur-md shadow-[0_0_15px_rgba(45,212,191,0.3)]">
                Trending Now
              </span>
              <span className="text-gray-600 dark:text-white/70 text-sm font-bold uppercase tracking-[0.2em] italic">
                {animes[currentIndex]?.status === "Currently Airing"
                  ? "Broadcasting"
                  : animes[currentIndex]?.status || "Season Highlight"}
              </span>
            </div>

            {/* Responsive, scalable typography with line clamp and break-words to prevent overflow */}
            <h1
              className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl xl:text-7xl font-black text-white leading-[0.95] tracking-tighter uppercase italic drop-shadow-[0_10px_10px_rgba(0,0,0,0.85)] overflow-hidden wrap-break-word"
              style={{
                display: "-webkit-box",
                WebkitLineClamp: 3,
                WebkitBoxOrient: "vertical",
                overflow: "hidden",
                textOverflow: "ellipsis",
              }}
              title={animes[currentIndex]?.title}
            >
              {animes[currentIndex]?.title}
            </h1>

            <p className="text-xl md:text-2xl text-gray-200 max-w-3xl line-clamp-3 font-medium leading-[1.6] drop-shadow-[0_5px_5px_rgba(0,0,0,0.9)]">
              {animes[currentIndex]?.synopsis}
            </p>

            <div className="flex flex-wrap items-center gap-6 pt-8">
              <button
                onClick={handleNavigate}
                className="relative group overflow-hidden bg-cyber-amber text-cyber-black px-12 py-5 rounded-full font-black uppercase text-sm tracking-widest flex items-center space-x-3 transition-transform hover:scale-105 shadow-[0_0_30px_rgba(245,158,11,0.4)]"
              >
                <span className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out"></span>
                <Play size={20} fill="currentColor" className="relative z-10" />
                <span className="relative z-10">Enter World</span>
              </button>
              <button
                onClick={handleNavigate}
                className="relative overflow-hidden border border-white/20 bg-black/40 backdrop-blur-md text-white px-12 py-5 rounded-full font-black uppercase text-sm tracking-widest hover:bg-white/10 transition-all duration-300 drop-shadow-[0_5px_5px_rgba(0,0,0,0.8)]"
              >
                Explore Lore
              </button>
            </div>
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Progress Indicators */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center space-x-3 z-30">
        {animes.map((_, idx) => (
          <button
            key={idx}
            onClick={() => setCurrentIndex(idx)}
            className={`transition-all duration-500 rounded-full ${
              idx === currentIndex
                ? "w-12 h-2 bg-cyber-teal shadow-[0_0_10px_rgba(45,212,191,0.6)]"
                : "w-2 h-2 bg-white/30 hover:bg-white/60"
            }`}
            aria-label={`Go to slide ${idx + 1}`}
          />
        ))}
      </div>
    </section>
  );
};

export default HeroCinematic;

import React from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext.jsx";
import { useTheme } from "../context/ThemeContext.jsx";
import { LogOut, User, Search, Tv } from "lucide-react";
import { motion } from "framer-motion";

const Navbar = () => {
  const { user, logout } = useAuth();
  const { theme } = useTheme();
  const navigate = useNavigate();

  return (
    <nav className="bg-cyber-black/40 backdrop-blur-xl sticky top-0 z-50 border-b border-white/5 shadow-xs transition-colors duration-500">
      <div className="container mx-auto px-4 sm:px-6 h-20 flex justify-between items-center">
        <Link to="/" className="flex items-center space-x-2 group">
          <motion.div
            whileHover={{ rotate: 360 }}
            transition={{ duration: 0.5 }}
            className="text-cyber-teal"
          >
            <Tv size={32} />
          </motion.div>
          <span className="text-xl sm:text-2xl font-black bg-gradient-to-r from-cyber-teal to-cyber-amber bg-clip-text text-transparent italic tracking-normal">
            LastEpisode
          </span>
        </Link>

        <div className="flex items-center space-x-4 sm:space-x-8">
          <Link
            to="/search"
            className="text-gray-600 dark:text-gray-400 hover:text-cyber-teal dark:hover:text-cyber-teal transition-colors font-bold uppercase text-xs tracking-widest flex items-center space-x-1"
          >
            <Search size={18} />
            <span className="hidden md:inline">Discover</span>
          </Link>

          {user && (
            <Link
              to="/dashboard"
              className="text-gray-600 dark:text-gray-400 hover:text-cyber-teal dark:hover:text-cyber-teal transition-colors font-bold uppercase text-xs tracking-widest flex items-center space-x-1"
            >
              <User size={18} />
              <span className="hidden md:inline">Library</span>
            </Link>
          )}

          <div className="h-6 w-px bg-gray-800" />

          {user ? (
            <button
              onClick={() => {
                logout();
                navigate("/login");
              }}
              className="text-gray-500 hover:text-red-500 transition-colors"
            >
              <LogOut size={20} />
            </button>
          ) : (
            <Link
              to="/login"
              className="relative px-4 sm:px-6 py-2 group overflow-hidden rounded-full font-bold text-xs sm:text-sm uppercase tracking-widest"
            >
              <span className="absolute inset-0 bg-cyber-teal transition-transform duration-300 group-hover:scale-105" />
              <span className="relative text-cyber-black">Join Hive</span>
            </Link>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from "react";
import { motion } from "framer-motion";

const PageTransition = ({ children }) => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      transition={{
        duration: 0.5,
        ease: [0.22, 1, 0.36, 1],
      }}
    >
      {children}
    </motion.div>
  );
};

export default PageTransition;

