  return (
    <div className="min-h-[90vh] flex items-center justify-center p-6 relative overflow-hidden">
      {/* Cinematic Background Elements */}
      <div className="absolute top-1/4 -left-20 w-96 h-96 bg-cyber-teal/10 rounded-full blur-[120px] animate-pulse-slow" />
      <div className="absolute bottom-1/4 -right-20 w-96 h-96 bg-cyber-amber/10 rounded-full blur-[120px] animate-pulse-slow" />

      <motion.div
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        className="w-full max-w-lg bg-white/40 dark:bg-cyber-gray/40 backdrop-blur-3xl p-12 rounded-[50px] border border-white/20 shadow-2xl relative z-10"
