        <div className="text-center mb-10">
          <motion.div
            initial={{ y: -20 }}
            animate={{ y: 0 }}
            className="inline-flex p-4 rounded-3xl bg-cyber-teal/10 text-cyber-teal mb-6 border border-cyber-teal/20"
          >
            <ShieldCheck size={40} />
          </motion.div>
          <h2 className="text-4xl font-black dark:text-white uppercase italic tracking-tighter mb-2">
            {isLogin ? "Protocol: Access" : "Create Identity"}
          </h2>
          <p className="text-gray-500 dark:text-gray-400 font-bold uppercase tracking-[0.2em] text-[10px]">
            Authentication Server v2.4.0
          </p>
        </div>

        {error && (
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
