          <AnimatePresence mode="wait">
            {!isLogin && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: "auto", opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                className="relative"
              >
                <User
                  className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"
                  size={20}
                />
                <input
                  type="text"
                  placeholder="USERNAME"
                  required
                  className="w-full pl-12 pr-4 py-5 bg-gray-50 dark:bg-cyber-black/50 border border-gray-100 dark:border-gray-800 rounded-2xl focus:ring-2 focus:ring-cyber-teal outline-none text-sm font-black tracking-widest uppercase dark:text-white transition-all"
                  value={formData.name}
                  onChange={(e) =>
                    setFormData({ ...formData, name: e.target.value })
                  }
                />
              </motion.div>
            )}
          </AnimatePresence>

          <div className="relative">
            <Mail
              className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"
              size={20}
            />
            <input
              type="email"
              placeholder="EMAIL ADDRESS"
              required
              className="w-full pl-12 pr-4 py-5 bg-gray-50 dark:bg-cyber-black/50 border border-gray-100 dark:border-gray-800 rounded-2xl focus:ring-2 focus:ring-cyber-teal outline-none text-sm font-black tracking-widest uppercase dark:text-white transition-all"
              value={formData.email}
              onChange={(e) =>
                setFormData({ ...formData, email: e.target.value })
              }
            />
          </div>

          <div className="relative">
            <Lock
              className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"
              size={20}
            />
            <input
              type="password"
              placeholder="ACCESS CODE"
              required
              className="w-full pl-12 pr-4 py-5 bg-gray-50 dark:bg-cyber-black/50 border border-gray-100 dark:border-gray-800 rounded-2xl focus:ring-2 focus:ring-cyber-teal outline-none text-sm font-black tracking-widest uppercase dark:text-white transition-all"
              value={formData.password}
              onChange={(e) =>
                setFormData({ ...formData, password: e.target.value })
              }
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full py-5 bg-cyber-teal text-cyber-black rounded-2xl font-black uppercase tracking-widest text-sm flex items-center justify-center space-x-3 hover:scale-[1.02] active:scale-95 transition-all shadow-xl shadow-cyber-teal/20"
          >
            <span>{loading ? "SYNCING..." : "INITIATE ACCESS"}</span>
            <ArrowRight size={20} />
          </button>
        </form>

        <div className="mt-10 text-center">
          <p className="text-gray-500 dark:text-gray-400 font-bold uppercase tracking-widest text-[10px] mb-4">
            {isLogin ? "No identity found?" : "Already synchronized?"}
