          <button
            onClick={() => setIsLogin(!isLogin)}
            className="text-cyber-teal font-black uppercase tracking-widest text-xs hover:underline"
          >
            {isLogin ? "Create New Profile" : "Access Existing Node"}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

